solution_code:
#include <stdio.h>

int get_value(int *p) {
    return *p;
}

void set_value(int *p, int val) {
    *p = val;
}

int main(void) {
    {
        int x = 42;
        printf("%d\n", (int)(get_value(&x)));
    }
    {
        int x = 0;
        set_value(&x, 99);
        printf("%d\n", (int)(x));
    }
    {
        int x = 10;
        set_value(&x, 20);
        printf("%d\n", (int)(get_value(&x)));
    }
    {
        int x = -50;
        printf("%d\n", (int)(get_value(&x)));
    }
    return 0;
}

