 * Declarer un pointeur vers float et dereferencement
 * L'operateur & donne l'adresse, * lit la valeur pointee.
 * =========================================================== */
void example_float_ptr(void) {
    float temperature = 36.6f;
    float *fp = &temperature;
    printf("temperature = %.1f\n", temperature);
    printf("via *fp     = %.1f\n", *fp);
    printf("fp == &temperature : %d\n", (fp == &temperature));
}
